long long solve(std::vector<long long> nums) {
    int n = nums.size();
    long long max_val = 0;

    // Try all possible ways to assign elements to A, B, C
    for (int i = 0; i < (1 << n); ++i) {
        // i represents the assignment of elements to A, B, C
        // bit j: 0 -> A, 1 -> B, 2 -> C
        long long xor_a = 0, and_b = 0, xor_c = 0;
        for (int j = 0; j < n; ++j) {
            int assign = (i >> j) & 3; // 0, 1, or 2
            long long num = nums[j];
            if (assign == 0) {
                xor_a ^= num;
            } else if (assign == 1) {
                and_b &= num;
                if (and_b == 0) and_b = 0;
            } else {
                xor_c ^= num;
            }
        }
        long long current = xor_a + and_b + xor_c;
        if (current > max_val) {
            max_val = current;
        }
    }

    return max_val;
}
